Bash(node -e "
const { chromium } = require\('playwright'\);
\(async \(\) => {
  const browser = await chromium.launch\({ headless: true }\);
  const page = await browser.newPage\({ viewport: { width: 1400, height: 900 } }\);
  await page.goto\('http://localhost:5175/vehicle/8b09175b-4315-4d24-8786-087ca1cf7d97', { waitUntil: 'networkidle', timeout: 30000 }\);
  await page.waitForTimeout\(4000\);

  // Check hero element
  const heroInfo = await page.evaluate\(\(\) => {
    const hero = document.getElementById\('vehicle-hero'\);
    if \(!hero\) return 'hero element not found';
    const rect = hero.getBoundingClientRect\(\);
    const style = window.getComputedStyle\(hero\);
    const children = hero.innerHTML.substring\(0, 500\);
    return {
      rect: { top: rect.top, left: rect.left, width: rect.width, height: rect.height },
      display: style.display,
      visibility: style.visibility,
      overflow: style.overflow,
      children: children,
      childCount: hero.childElementCount
    };
  }\);
  console.log\(JSON.stringify\(heroInfo, null, 2\)\);
  await browser.close\(\);
}\)\(\).catch\(e => console.error\(e\)\);
" 2>&1)

