-- Run in batches of 5000, up to 40K total
DO $$
DECLARE
  batch_num INT := 0;
  batch_count INT;
  total_processed INT := 0;
  total_fields INT := 0;
BEGIN
  -- Triggers already disabled
  LOOP
    batch_num := batch_num + 1;
    SELECT COUNT\(*\), COALESCE\(SUM\(out_fields_applied\), 0\)
    INTO batch_count, batch_count -- reuse variable temporarily
    FROM enrich_bj_from_snapshots\(5000\);

    -- Actually need separate vars
    EXIT WHEN batch_count = 0;

    total_processed := total_processed + batch_count;
    RAISE NOTICE 'Batch %: processed % vehicles \(total: %\)', batch_num, batch_count, total_processed;

    -- Breathe
    PERFORM pg_sleep\(0.5\);

    -- Safety: max 40K
    EXIT WHEN total_processed >= 40000;
  END LOOP;

  RAISE NOTICE 'DONE: % total vehicles processed', total_processed;
END $$;
SQL)
